-- Realistic MPPT Demo Data for Station 12
-- 5A Solar Charge Controller, 30W 18V Panel, 12V 18Ah Battery
-- 577 records at 5-min intervals

BEGIN;

-- Delete existing demo data
DELETE FROM weather_data WHERE station_id = 4;


COMMIT;

-- Verify
SELECT count(*), min(mppt_solar_voltage), max(mppt_solar_voltage), min(mppt_solar_current), max(mppt_solar_current), min(mppt_solar_power), max(mppt_solar_power), min(mppt_battery_voltage), max(mppt_battery_voltage), min(mppt_load_current), max(mppt_load_current), min(mppt_board_temp), max(mppt_board_temp) FROM weather_data WHERE station_id = 4;
